patch:
diff --git a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
index bbfed2ac2c09..1f40d86b6aad 100644
--- a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
+++ b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
@@ -661,8 +661,13 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
     auto TypeSize = DL.getTypeStoreSize(Ty);
     if (!TypeSize.isScalable() && Offset) {
       int64_t Size = TypeSize.getFixedValue();
-      return ConstantRange(APInt(64, *Offset, true),
-                           APInt(64, *Offset + Size, true));
+      APInt Lower(64, *Offset, /*isSigned=*/true);
+      APInt Addend(64, Size, /*isSigned=*/true);
+      bool Ov = false;
+      APInt Upper = Lower.sadd_ov(Addend, Ov);
+      if (Ov || !Lower.slt(Upper))
+        return std::nullopt;
+      return ConstantRange(Lower, Upper);
     }
     return std::nullopt;
   };
@@ -672,9 +677,13 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
     auto *ConstantLength = dyn_cast<ConstantInt>(Length);
     if (ConstantLength && Offset &&
         ConstantLength->getValue().isStrictlyPositive()) {
-      return ConstantRange(
-          APInt(64, *Offset, true),
-          APInt(64, *Offset + ConstantLength->getSExtValue(), true));
+      APInt Lower(64, *Offset, /*isSigned=*/true);
+      APInt Addend(64, ConstantLength->getSExtValue(), /*isSigned=*/true);
+      bool Ov = false;
+      APInt Upper = Lower.sadd_ov(Addend, Ov);
+      if (Ov || !Lower.slt(Upper))
+        return std::nullopt;
+      return ConstantRange(Lower, Upper);
     }
     return std::nullopt;
   };
@@ -735,9 +744,15 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
         ConstantRangeList AccessRanges;
         Attribute Attr = CB->getParamAttr(ArgNo, Attribute::Initializes);
         ConstantRangeList CBCRL = Attr.getValueAsConstantRangeList();
-        for (ConstantRange &CR : CBCRL)
-          AccessRanges.insert(ConstantRange(CR.getLower() + *ArgUse.Offset,
-                                            CR.getUpper() + *ArgUse.Offset));
+        for (ConstantRange &CR : CBCRL) {
+          APInt Off(64, *ArgUse.Offset, /*isSigned=*/true);
+          bool OvL = false, OvU = false;
+          APInt NewLower = CR.getLower().sadd_ov(Off, OvL);
+          APInt NewUpper = CR.getUpper().sadd_ov(Off, OvU);
+          if (OvL || OvU || !NewLower.slt(NewUpper))
+            continue; // Skip ranges we can't safely represent.
+          AccessRanges.insert(ConstantRange(NewLower, NewUpper));
+        }
         return {Access, AccessRanges};
       }
     }

